import React, { useState, useEffect } from 'react';
import {
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
} from 'recharts';
import api from '../utils/api';

interface CanalCount {
  canal: string;
  _count: number;
}

interface CategorieCount {
  categorie: string;
  _count: number;
}

interface RecentLead {
  nom: string;
  score?: number;
  categorie?: string;
  createdAt: string;
}

interface Stats {
  totalLeads: number;
  totalMessages: number;
  openRate: number;
  clickRate: number;
  replyRate: number;
  byCanal: CanalCount[];
  byCategorie: CategorieCount[];
  recentLeads: RecentLead[];
}

interface ChartDataPoint {
  name: string;
  value: number;
}

const PIE_COLORS: string[] = ['#f87171', '#fb923c', '#60a5fa'];

const CATEGORIE_BG: Record<string, string> = {
  CHAUD: 'bg-red-500/10 text-red-400',
  TIEDE: 'bg-amber-500/10 text-amber-400',
  FROID: 'bg-blue-500/10 text-blue-400',
};

function getInitials(nom: string): string {
  return nom
    .split(' ')
    .map((w) => w[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);
}

function getAvatarColor(nom: string): string {
  const colors = [
    'bg-indigo-500/20 text-indigo-400',
    'bg-violet-500/20 text-violet-400',
    'bg-pink-500/20 text-pink-400',
    'bg-cyan-500/20 text-cyan-400',
    'bg-teal-500/20 text-teal-400',
    'bg-emerald-500/20 text-emerald-400',
  ];
  let hash = 0;
  for (let i = 0; i < nom.length; i++) hash = nom.charCodeAt(i) + ((hash << 5) - hash);
  return colors[Math.abs(hash) % colors.length];
}

interface StatCardProps {
  label: string;
  value: number;
  unit?: string;
  icon: React.ReactElement;
  accent?: string;
}

function StatCard({ label, value, unit = '', icon, accent = 'text-zinc-400' }: StatCardProps): React.ReactElement {
  return (
    <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5 flex flex-col gap-3">
      <div className={`w-8 h-8 rounded-lg bg-zinc-800 flex items-center justify-center ${accent}`}>
        {icon}
      </div>
      <div>
        <p className="text-2xl font-bold text-zinc-100 tabular-nums leading-none">
          {value}
          <span className="text-zinc-500 text-sm font-normal ml-0.5">{unit}</span>
        </p>
        <p className="text-xs text-zinc-500 mt-1">{label}</p>
      </div>
    </div>
  );
}

const CustomTooltip = ({ active, payload, label }: any): React.ReactElement | null => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-zinc-900 border border-zinc-800 rounded-lg px-3 py-2 text-xs shadow-xl">
        <p className="text-zinc-400 mb-0.5">{label || payload[0].name}</p>
        <p className="text-zinc-100 font-semibold">{payload[0].value}</p>
      </div>
    );
  }
  return null;
};

export default function MonitorPage(): React.ReactElement {
  const [stats, setStats] = useState<Stats | null>(null);

  const fetchStats = async (): Promise<void> => {
    try {
      const { data } = await api.get('/monitor');
      setStats(data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchStats();
    const interval = setInterval(fetchStats, 10000);
    return () => clearInterval(interval);
  }, []);

  if (!stats) {
    return (
      <div className="flex items-center justify-center h-full py-32">
        <div className="flex flex-col items-center gap-3 text-zinc-600">
          <svg className="animate-spin w-6 h-6 text-zinc-700" viewBox="0 0 24 24" fill="none">
            <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" strokeDasharray="40" strokeDashoffset="10" />
          </svg>
          <span className="text-xs">Chargement des statistiques...</span>
        </div>
      </div>
    );
  }

  const canalData: ChartDataPoint[] = stats.byCanal.map((c) => ({ name: c.canal, value: c._count }));
  const categorieData: ChartDataPoint[] = stats.byCategorie.map((c) => ({ name: c.categorie, value: c._count }));

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h1 className="text-base font-semibold text-zinc-100">Monitoring</h1>
        <div className="flex items-center gap-1.5">
          <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
          <span className="text-xs text-zinc-500">Live — mise à jour toutes les 10s</span>
        </div>
      </div>

      {/* Stat Cards */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        <StatCard
          label="Total Leads"
          value={stats.totalLeads}
          accent="text-indigo-400"
          icon={
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
              <circle cx="9" cy="7" r="4" />
              <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
              <path d="M16 3.13a4 4 0 0 1 0 7.75" />
            </svg>
          }
        />
        <StatCard
          label="Messages envoyés"
          value={stats.totalMessages}
          accent="text-violet-400"
          icon={
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
              <line x1="22" y1="2" x2="11" y2="13" />
              <polygon points="22 2 15 22 11 13 2 9 22 2" />
            </svg>
          }
        />
        <StatCard
          label="Taux d'ouverture"
          value={stats.openRate}
          unit="%"
          accent="text-emerald-400"
          icon={
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
              <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" />
              <circle cx="12" cy="12" r="3" />
            </svg>
          }
        />
        <StatCard
          label="Taux de clic"
          value={stats.clickRate}
          unit="%"
          accent="text-amber-400"
          icon={
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
              <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
            </svg>
          }
        />
        <StatCard
          label="Taux de réponse"
          value={stats.replyRate}
          unit="%"
          accent="text-cyan-400"
          icon={
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.75" strokeLinecap="round" strokeLinejoin="round">
              <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
            </svg>
          }
        />
      </div>

      {/* Charts Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-5">
            Leads par catégorie
          </h2>
          <ResponsiveContainer width="100%" height={200}>
            <PieChart>
              <Pie
                data={categorieData}
                dataKey="value"
                nameKey="name"
                cx="50%"
                cy="50%"
                outerRadius={75}
                innerRadius={40}
                paddingAngle={3}
                label={({ name, value }: { name: string; value: number }) => `${name}: ${value}`}
                labelLine={{ stroke: '#52525b', strokeWidth: 1 }}
              >
                {categorieData.map((_, i) => (
                  <Cell key={i} fill={PIE_COLORS[i % PIE_COLORS.length]} stroke="transparent" />
                ))}
              </Pie>
              <Tooltip content={<CustomTooltip />} />
            </PieChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
          <h2 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-5">
            Messages par canal
          </h2>
          <ResponsiveContainer width="100%" height={200}>
            <BarChart data={canalData} barCategoryGap="35%">
              <XAxis dataKey="name" stroke="#3f3f46" tick={{ fill: '#71717a', fontSize: 11 }} axisLine={false} tickLine={false} />
              <YAxis stroke="#3f3f46" tick={{ fill: '#71717a', fontSize: 11 }} axisLine={false} tickLine={false} width={30} />
              <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(99,102,241,0.06)' }} />
              <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Recent Leads */}
      <div className="bg-zinc-900 rounded-xl border border-zinc-800 p-5">
        <h2 className="text-xs font-semibold text-zinc-400 uppercase tracking-wider mb-4">
          Derniers leads
        </h2>
        <div className="space-y-1">
          {stats.recentLeads.length === 0 ? (
            <p className="text-xs text-zinc-600 py-4 text-center">Aucun lead récent</p>
          ) : (
            stats.recentLeads.map((l, i) => (
              <div
                key={i}
                className="flex items-center gap-3 py-2.5 px-1 rounded-lg hover:bg-zinc-800/50 transition-colors group"
              >
                {/* Avatar */}
                <div className={`w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-semibold flex-shrink-0 ${getAvatarColor(l.nom)}`}>
                  {getInitials(l.nom)}
                </div>
                <span className="text-xs font-medium text-zinc-200 flex-1 min-w-0 truncate">{l.nom}</span>
                <span className="text-xs text-zinc-600 tabular-nums">Score {l.score ?? '—'}/10</span>
                {l.categorie && (
                  <span className={`text-[10px] px-2 py-0.5 rounded-md font-medium ${CATEGORIE_BG[l.categorie] || 'bg-zinc-800 text-zinc-400'}`}>
                    {l.categorie}
                  </span>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
